// Solution
import * as readline from 'readline';
const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
export function solve(input: string) {
    const numbers = input.split(' ').map(Number);
    const calculator = new MathCalculator<number>();
    let result = numbers[0];
    for (let i = 1; i < numbers.length; i += 2) {
        switch (numbers[i]) {
            case '+':
                result = calculator.add(result, numbers[i + 1]);
                break;
            case '-':
                result = calculator.subtract(result, numbers[i + 1]);
                break;
            case '*':
                result = calculator.multiply(result, numbers[i + 1]);
                break;
            case '/':
                if (numbers[i + 1] === 0) {
                    return 'Error: division by zero';
                }
                result = calculator.divide(result, numbers[i + 1]);
                break;
        }
    }
    return result.toString();
}
rl.on('line', (input) => {
    console.log(solve(input));
});
